def calculate_file_positions(file, sugiyama_positions, parent_pos, local_idx, siblings, tree_offset, global_idx):
    """
    Calculate file positions based on priority order: Sugiyama → Backend → Local.

    Args:
        file (dict): File metadata including visual hints.
        sugiyama_positions (dict): Sugiyama positions if available.
        parent_pos (dict): Parent folder position.
        local_idx (int): Index of the file in its sibling list.
        siblings (list): List of sibling files.
        tree_offset (int): Offset for tree visualization.
        global_idx (int): Global index for logging.

    Returns:
        dict: Calculated positions (x, y, z).
    """
    x, y, z = 0, 0, 0

    if sugiyama_positions and sugiyama_positions.get(file.id):
        # Sugiyama mode
        sp = sugiyama_positions[file.id]
        x = sp.x + tree_offset
        y = sp.y
        z = 0
        if global_idx < 5:
            print(f"[FILE] {file.name} using Sugiyama Y={y:.0f}")
    elif file.get('visual_hints', {}).get('layout_hint'):
        # Backend positions
        hint = file['visual_hints']['layout_hint']
        x = (hint.get('expected_x', parent_pos.x)) + tree_offset
        y = hint.get('expected_y', parent_pos.y + 40)
        z = 0
        if global_idx < 5:
            print(f"[FILE] {file.name} using backend Y={y:.0f}")
    else:
        # Local calculation for orphan files or missing hints
        theta = local_idx * FILE_GOLDEN_ANGLE
        radius = FILE_RADIUS_BASE + Math.sqrt(local_idx + 1) * FILE_RADIUS_GROWTH
        x = parent_pos.x + Math.cos(theta) * radius
        z = 0
        y = calculate_file_y(file, local_idx, siblings, parent_pos.y)
        print(f"[FILE] {file.name} using LOCAL Y={y:.0f} (no backend hint)")

    return {'x': x, 'y': y, 'z': z}
```

