describe('Tree Renderer Position Calculation', () => {
    test('Should use Sugiyama positions if available', () => {
        const file = { id: 'file1', name: 'config.py' };
        const sugiyamaPositions = { file1: { x: 100, y: 200 } };
        const parentPos = { x: 0, y: 0 };
        const positions = calculateFilePositions(file, sugiyamaPositions, parentPos, 0, [], 0, 0);
        expect(positions.y).toBe(200);
    });

    test('Should use backend layout_hint if no Sugiyama positions', () => {
        const file = { id: 'file2', name: 'main.py', visual_hints: { layout_hint: { expected_y: 180 } } };
        const parentPos = { x: 0, y: 0 };
        const positions = calculateFilePositions(file, null, parentPos, 0, [], 0, 0);
        expect(positions.y).toBe(180);
    });

    test('Should use local calculation for orphan files', () => {
        const file = { id: 'file3', name: 'orphan.txt' };
        const parentPos = { x: 0, y: 0 };
        const positions = calculateFilePositions(file, null, parentPos, 0, [], 0, 0);
        expect(positions.y).toBeGreaterThan(0);
    });
});
